-- ============================================
-- 导入三份问卷数据
-- ============================================

USE `cc_survey_db`;

-- 获取管理员用户ID
SET @admin_id = (SELECT id FROM sys_user WHERE username = 'admin' LIMIT 1);

-- 1. 企业调研问卷
INSERT INTO `survey_template` (`uuid`, `title`, `description`, `form_id`, `schema_json`, `status`, `version`, `created_by`, `create_time`, `publish_time`)
VALUES (
    REPLACE(UUID(), '-', ''),
    '企业调研问卷',
    '企业基础信息调研问卷，包含企业核心信息、数字化人员、资质荣誉等内容',
    'enterprise_survey_form',
    '{"title": "企业调研问卷", "fields": [{"id": "q1", "type": "multi-input", "label": "1、企业核心基础信息", "required": true, "subFields": [{"id": "q1_1", "type": "input", "label": "企业名称", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z0-9（）\\\\(\\\\)\\\\s]{2,50}$", "required": true, "placeholder": "请输入企业全称（支持中英文、数字及括号）", "errorMessage": "企业名称格式不正确，仅支持中英文、数字及括号，长度2-50位"}, {"id": "q1_2", "type": "input", "label": "社会统一信用代码", "pattern": "^[0-9A-HJ-NP-QRTUWXY]{2}\\\\d{6}[0-9A-HJ-NP-QRTUWXY]{10}$", "required": true, "placeholder": "请输入18位社会统一信用代码", "errorMessage": "信用代码格式错误（18位数字或大写字母，不含I、O、Z、S、V）"}]}, {"id": "q2", "type": "radio", "label": "2、单位性质", "options": [{"label": "国有", "score": 0, "value": "A"}, {"label": "民营", "score": 0, "value": "B"}, {"label": "外资", "score": 0, "value": "C"}, {"label": "其他", "score": 0, "value": "D", "extraInput": {"id": "q2_other_desc", "hint": "请务必补充具体说明", "required": true, "inputType": "text", "placeholder": "请具体说明单位性质", "errorMessage": ""其他"项的具体说明不能为空"}}], "required": true}, {"id": "q3", "hint": "地址精确到门牌号", "type": "input", "label": "3、单位地址", "required": true, "inputType": "text", "placeholder": "请输入"}, {"id": "q4", "type": "date", "label": "4、成立时间", "dateType": "date", "required": true, "placeholder": "选择日期"}, {"id": "q5", "hint": "按照万元的标准填写", "type": "input", "label": "5、注册资本（万元）", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q6", "type": "input", "label": "6、法定代表人", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z]{1,20}$", "required": true, "inputType": "text", "placeholder": "请输入中英文（20字符以内）", "errorMessage": "仅支持中英文，且长度在20个字符以内"}, {"id": "q7", "hint": "交社保的人数", "type": "radio", "label": "7、员工数量", "options": [{"label": "1-50人", "score": 0, "value": "A"}, {"label": "51-100人", "score": 0, "value": "B"}, {"label": "101-500人", "score": 0, "value": "C"}, {"label": "501-1000人", "score": 0, "value": "D"}, {"label": "1001-5000人", "score": 0, "value": "E"}, {"label": "5001人以上", "score": 0, "value": "F"}], "required": true, "extraInput": {"id": "q7_exact_num", "hint": "此项必答，请输入精确数字以便我们统计", "required": true, "inputType": "number", "placeholder": "请输入具体精确数字", "validatorRule": {"logic": "q7 === '\''A'\'' ? (q7_exact_num >= 1 && q7_exact_num <= 50) : q7 === '\''B'\'' ? (q7_exact_num >= 51 && q7_exact_num <= 100) : q7 === '\''C'\'' ? (q7_exact_num >= 101 && q7_exact_num <= 500) : q7 === '\''D'\'' ? (q7_exact_num >= 501 && q7_exact_num <= 1000) : q7 === '\''E'\'' ? (q7_exact_num >= 1001 && q7_exact_num <= 5000) : q7 === '\''F'\'' ? (q7_exact_num >= 5001) : true", "message": "输入的精确数字与所选范围不符"}}}, {"id": "q8", "hint": "管系统、弄设备、搞数据、使用电子设备的企业人员", "type": "multi-input", "label": "8、数字化人员", "required": true, "subFields": [{"id": "q8_1", "type": "input", "label": "专职人员数量（人）", "required": true, "inputType": "number"}, {"id": "q8_2", "type": "input", "label": "兼职人员数量（人）", "required": true, "inputType": "number"}]}, {"id": "q9", "type": "input", "label": "9、主营业务产品", "required": true, "inputType": "text", "placeholder": "请输入"}, {"id": "q10", "type": "input", "label": "10、资产总额（万元）", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q11", "type": "multi-input", "label": "11、联系人信息", "required": true, "subFields": [{"id": "q11_1", "type": "input", "label": "联系人姓名", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z]{1,20}$", "required": true, "inputType": "text", "placeholder": "请输入中英文（20字符以内）", "errorMessage": "仅支持中英文，且长度在20个字符以内"}, {"id": "q11_2", "type": "input", "label": "项目负责人", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z]{1,20}$", "required": true, "inputType": "text", "placeholder": "请输入中英文（20字符以内）", "errorMessage": "仅支持中英文，且长度在20个字符以内"}, {"id": "q11_3", "type": "input", "label": "业务对接人", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z]{1,20}$", "required": true, "inputType": "text", "placeholder": "请输入中英文（20字符以内）", "errorMessage": "仅支持中英文，且长度在20个字符以内"}, {"id": "q11_4", "type": "input", "label": "联系人电话", "pattern": "^1(3\\\\d|4[5-9]|5[0-35-9]|6[567]|7[0-8]|8\\\\d|9[0-35-9])\\\\d{8}$", "required": true, "inputType": "text", "placeholder": "请输入11位手机号码", "errorMessage": "请输入有效的11位手机号码"}]}, {"id": "q12", "type": "radio", "label": "12、所属试点行业", "options": [{"label": "基础化工", "score": 0, "value": "A"}, {"label": "生物医药", "score": 0, "value": "B"}, {"label": "通用装备", "score": 0, "value": "C"}, {"label": "电子设备", "score": 0, "value": "D"}, {"label": "富硒绿色食品加工", "score": 0, "value": "E"}, {"label": "中药材加工及医药制造", "score": 0, "value": "F"}, {"label": "绿色建材及新材料制造 ", "score": 0, "value": "G"}, {"label": "电气及其他装备制造", "score": 0, "value": "H"}, {"label": "纺织服装服饰", "score": 0, "value": "I"}, {"label": "泵阀", "score": 0, "value": "J"}], "required": true}, {"id": "q13", "type": "multi-input", "label": "13、近三年营业收入（万元）", "required": true, "subFields": [{"id": "q13_1", "type": "input", "label": "2023年", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q13_2", "type": "input", "label": "2024年", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q13_3", "type": "input", "label": "2025年", "required": true, "inputType": "number", "placeholder": "单位为万元"}]}, {"id": "q14", "hint": "包括各种数字化设备的相关投入（电脑、路由器、购买相关软件、防火墙、数字化人员等）", "type": "multi-input", "label": "14、近三年数字化投入（万元）", "required": true, "subFields": [{"id": "q14_1", "type": "input", "label": "2023年", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q14_2", "type": "input", "label": "2024年", "required": true, "inputType": "number", "placeholder": "单位为万元"}, {"id": "q14_3", "type": "input", "label": "2025年", "required": true, "inputType": "number", "placeholder": "单位为万元"}]}, {"id": "q15", "type": "input", "label": "15、发明专利数量", "required": true, "inputType": "number", "placeholder": "请输入数字"}, {"id": "q16", "type": "checkbox", "label": "16、研究机构设置", "options": [{"label": "有技术中心", "score": 0, "value": "A"}, {"label": "有其他研究机构", "score": 0, "value": "B", "extraInput": {"id": "q16_other_reason", "required": true, "inputType": "text", "placeholder": "请详细说明", "errorMessage": "请务必填写"}}, {"label": "无", "score": 0, "value": "C"}], "required": true}, {"id": "q17", "type": "checkbox", "label": "17、企业荣誉资质（多选，至少需提供一份证书附件）", "options": [{"label": "专精特新"小巨人"企业", "value": "A"}, {"label": "省级"专精特新"企业", "value": "B"}, {"label": "创新型中小企业", "value": "C"}, {"label": "两化融合贯标企业", "value": "D"}, {"label": "DCMM贯标", "value": "E"}, {"label": "其他资质:国家高新技术企业", "value": "F"}], "required": true, "extraInput": {"id": "q17_cert_upload", "hint": "温馨提示：请上传相关资质证书证明文件复印件或原件扫描件", "type": "upload", "accept": ".jpg,.png,.pdf,.zip", "action": "/api/upload", "btnText": "上传资质证书", "required": true}}, {"id": "q18", "hint": "请上传公司的设备台账文件进行填写", "type": "upload", "label": "18、生产设备列表上传", "action": "/api/upload", "required": true}, {"id": "q19", "hint": "请上传按照上述调研内容所填写对应的软件列表台账进行填写", "type": "upload", "label": "19、数字化系统列表上传", "action": "/api/upload", "required": true}, {"id": "q20", "hint": "请上传公司组织架构图，组织架构图需要附有组织各部门名称和每个部门负责人名字", "type": "upload", "label": "20、公司组织架构图上传", "action": "/api/upload", "required": true}, {"id": "q21", "hint": "请上传公司工艺流程图，工艺流程图需要描述主要业务产品的生产流程工艺", "type": "upload", "label": "21、工艺流程图上传", "action": "/api/upload", "required": true}]}',
    1,
    1,
    @admin_id,
    NOW(),
    NOW()
);

-- 2. 成效测评表
INSERT INTO `survey_template` (`uuid`, `title`, `description`, `form_id`, `schema_json`, `status`, `version`, `created_by`, `create_time`, `publish_time`)
VALUES (
    REPLACE(UUID(), '-', ''),
    '成效测评表',
    '企业数字化成效测评问卷，包含网络建设、设备联网、数据采集、信息系统、安全等内容',
    'effectiveness_evaluation_form',
    '{"title": "成效测评表", "fields": [{"id": "q1", "type": "input", "label": "1、企业公司名称", "pattern": "^[\\\\u4e00-\\\\u9fa5a-zA-Z0-9（）\\\\(\\\\)\\\\s]{2,50}$", "required": true, "placeholder": "请输入企业全称（支持中英文、数字及括号）", "errorMessage": "企业名称格式不正确（支持中英文数字括号，2-50位）"}, {"id": "q2", "type": "checkbox", "label": "2、网络建设", "options": [{"label": "无", "score": 0, "value": "A"}, {"label": "企业车间建成工控网络，支持自动化控制应用", "score": 2, "value": "B", "hint": "（选中此项请提供相应的网络拓扑图或证明）"}, {"label": "企业建成应用系统网络，实现大规模设备、人员与信息系统互联", "score": 2, "value": "C", "hint": "（选中此项请提供应用系统网络后台管理界面截图）"}, {"label": "企业建设/租用5G工业网络", "score": 2, "value": "D", "hint": "（选中此项请提供5G网络建设/租赁证明材料）"}, {"label": "网络全面覆盖生产现场与环节", "score": 2, "value": "E", "hint": "（选中此项请提供网络拓扑图）"}], "required": true, "extraInput": {"id": "q2_upload", "hint": "请上传网络建设相关证明材料", "type": "upload", "action": "/api/upload", "btnText": "点击上传", "required": true, "showWhen": "!q2.includes('\''A'\'')"}}, {"id": "q3", "hint": "可根据上传的台账文件里面的设备数量来进行填写", "type": "multi-input", "label": "3、设备联网", "required": true, "subFields": [{"id": "q3_1", "type": "input", "label": "全部设备数量（台）", "required": true, "inputType": "number"}, {"id": "q3_2", "type": "input", "label": "实现联网的生产设备数量（台）", "required": true, "inputType": "number", "validatorRule": {"logic": "Number(q3_2) <= Number(q3_1)", "message": "联网设备数量不能超过全部设备总数"}}, {"id": "q3_3", "type": "input", "label": "联网率（%）", "readonly": true, "required": true, "inputType": "number", "computeRule": "(q3_1 && q3_2 && q3_1 > 0) ? Number(((q3_2 / q3_1) * 100).toFixed(2)) : '\'''\''", "placeholder": "系统将自动计算，无需填写"}]}, {"id": "q4", "hint": "系统已根据上题填写的对应联网率自动为您选择了对应选项", "type": "radio", "label": "4、设备联网", "options": [{"label": "0-10%", "score": 0, "value": "A"}, {"label": "10%-20%", "score": 1.5, "value": "B"}, {"label": "20%-40%", "score": 3, "value": "C"}, {"label": "40%-60%", "score": 4.5, "value": "D"}, {"label": "60%-100%", "score": 6, "value": "E"}], "readonly": true, "required": true, "computeRule": "q3_3 !== '\'''\'' ? (q3_3 <= 10 ? '\''A'\'' : q3_3 <= 20 ? '\''B'\'' : q3_3 <= 40 ? '\''C'\'' : q3_3 <= 60 ? '\''D'\'' : '\''E'\'') : '\'''\''"}]}',
    1,
    1,
    @admin_id,
    NOW(),
    NOW()
);

-- 3. 应用场景现状评估表
INSERT INTO `survey_template` (`uuid`, `title`, `description`, `form_id`, `schema_json`, `status`, `version`, `created_by`, `create_time`, `publish_time`)
VALUES (
    REPLACE(UUID(), '-', ''),
    '应用场景现状评估表',
    '企业数字化应用场景现状评估，包含产品设计、工艺设计、营销管理、生产管控等16个维度',
    'enterprise_digital_maturity_evaluation',
    '{"title": "应用场景现状评估表", "fields": [{"id": "q_1", "label": "1、产品设计", "type": "radio", "required": true, "options": [{"label": "无", "value": "A", "score": 0, "hint": "（若选此项，无需提供佐证材料）"}, {"label": "运用仿真分析等技术实现产品试验验证或迭代优化", "value": "B", "score": 0, "hint": "（佐证材料：仿真分析界面截图）"}, {"label": "建立典型产品组件及关键零部件的标准库", "value": "C", "score": 0, "hint": "（佐证材料：标准库截图）"}, {"label": "应用信息化系统开展产品设计", "value": "D", "score": 0, "hint": "（佐证材料：产品设计信息化系统截图）"}, {"label": "通过设计软件工具辅助开展产品设计", "value": "E", "score": 0, "hint": "（佐证材料：设计软件工具界面截图）"}], "extraInput": {"id": "q_1_upload", "type": "upload", "action": "/api/upload", "hint": "请根据您选择的选项（非"无"），上传对应的佐证材料截图", "btnText": "点击上传佐证材料", "showWhen": "q_1 && q_1 !== '\''A'\''", "required": true}}, {"id": "q_2", "label": "2、工艺设计", "type": "radio", "required": true, "options": [{"label": "无", "value": "A", "score": 0}, {"label": "建立数据模型，运用三维仿真等技术", "value": "B", "score": 0}, {"label": "建立典型制造工艺流程知识库", "value": "C", "score": 0}, {"label": "应用信息化系统开展工艺设计", "value": "D", "score": 0}, {"label": "应用设计软件工具辅助开展工艺设计", "value": "E", "score": 0}], "extraInput": {"id": "q_2_upload", "type": "upload", "action": "/api/upload", "hint": "请上传佐证材料截图", "btnText": "点击上传佐证材料", "showWhen": "q_2 && q_2 !== '\''A'\''", "required": true}}, {"id": "q_3", "label": "3、营销管理", "type": "radio", "required": true, "options": [{"label": "无", "value": "A", "score": 0}, {"label": "使用人工智能等前沿技术实现数字化协同", "value": "B", "score": 0}, {"label": "基于销售信息化系统实现实时管控", "value": "C", "score": 0}, {"label": "使用信息化系统对营销信息进行规范化管理", "value": "D", "score": 0}, {"label": "借助信息技术工具对营销信息进行辅助记录", "value": "E", "score": 0}], "extraInput": {"id": "q_3_upload", "type": "upload", "action": "/api/upload", "hint": "请上传佐证材料截图", "btnText": "点击上传佐证材料", "showWhen": "q_3 && q_3 !== '\''A'\''", "required": true}}]}',
    1,
    1,
    @admin_id,
    NOW(),
    NOW()
);

SELECT '问卷导入完成' as status;
SELECT uuid, title, form_id, status FROM survey_template;
